import React, { useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import "./Register.css";

export default function Register() {
  const navigate = useNavigate();
  const [role, setRole] = useState("student");
  const [showSecret, setShowSecret] = useState(false);

  const handleRoleChange = (e) => {
    const selected = e.target.value;
    setRole(selected);
    setShowSecret(selected === "admin" || selected === "hr");
  };

  function handleRegister(e) {
    e.preventDefault();
    const name = e.target.name.value.trim();
    const roll = e.target.roll?.value.trim() || "";
    const email = e.target.email.value.trim();
    const pass = e.target.pass.value;
    const cpass = e.target.cpass.value;
    const selectedRole = e.target.role.value;
    const secret = e.target.secret?.value.trim();

    // ✅ Validate passwords
    if (pass !== cpass) {
      alert("Passwords do not match!");
      return;
    }

    // ✅ Validate secret for admin/hr
    if ((selectedRole === "admin" || selectedRole === "hr") && secret !== "connect@123") {
      alert("Invalid secret key for Admin/HR. Access denied.");
      return;
    }

    localStorage.setItem("userName", name);
    localStorage.setItem("rollNumber", roll);
    localStorage.setItem("email", email);
    localStorage.setItem("password", pass);
    localStorage.setItem("role", selectedRole);

    alert("Registration successful!");
    navigate("/dashboard");
  }

  return (
    <div className="split-layout">
      <div className="left-panel">
        <h1>🎓 Campus Connect</h1>
        <div className="tagline-box">
          <h2>Wide College Network</h2>
          <p>Favorite Space To Connect!</p>
        </div>
        <img
          src="https://img.freepik.com/premium-vector/graduation-students_1214-321.jpg"
          alt="Graduates"
          className="illustration"
        />
      </div>

      <div className="right-panel">
        <div className="form-box shadow-card">
          <div className="tabs">
            <Link to="/login" className="tab">Login</Link>
            <Link to="/register" className="tab active">Signup</Link>
          </div>

          <h2>Register</h2>
          <form onSubmit={handleRegister}>
            <label>Full Name</label>
            <input name="name" type="text" required />

            {role === "student" && (
              <>
                <label>University Roll Number</label>
                <input name="roll" type="text" required />
              </>
            )}

            <label>Email</label>
            <input name="email" type="email" required />

            <label>Password</label>
            <input name="pass" type="password" required />

            <label>Confirm Password</label>
            <input name="cpass" type="password" required />

            <label>Select Role</label>
            <select name="role" value={role} onChange={handleRoleChange} required>
              <option value="student">Student</option>
              <option value="admin">Admin</option>
              <option value="hr">HR</option>
            </select>

            {showSecret && (
              <>
                <label>Enter Secret Key</label>
                <input name="secret" type="password" placeholder="Ask Admin" required />
              </>
            )}

            <button type="submit">Register</button>
          </form>
          <p className="signup-cta">
            Already a user? <Link to="/login"><strong>Login</strong></Link>
          </p>
        </div>
      </div>
    </div>
  );
}
